import { createStreamText } from 'ai';
import { createVexMiddleware } from '@vex_dev/sdk';

const vexMiddleware = createVexMiddleware({
  orgId: 'ins-org-123',
  circuitBreaker: {
    timeout: 25000, // Vercel Edge limit
    maxFailures: 3,
    fallback: 'Processing complex request - simplified response generated.'
  },
  maxTokens: 4000
});

export async function POST(req: Request) {
  const { messages, tools } = await req.json();

  const result = await createStreamText({
    middleware: [vexMiddleware],
    model: openai('gpt-4o'),
    messages,
    tools,
    maxTokens: 4000
  });

  return result.toAIStreamResponse();
}
